import React from "react";

import CheckmarkCircle from "../CheckmarkCircle";
import CrossCircle from '../CrossCircle';

const Icon = props => {
  switch (props.name) {
    case "checkmarkcircle":
      return <CheckmarkCircle {...props} />;
    case "crosscircle":
      return <CheckmarkCircle {...props} />;
    default:
      return;
  }
};

export default Icon;
